const crypto = require('../src/crypto');

describe('Encryption', () => {
  const key = '0123456789abcdef0123456789abcdef';
  const plaintext = 'sensitive data';

  test('should encrypt data correctly', () => {
    const encrypted = crypto.encrypt(plaintext, key);
    expect(encrypted).toBeDefined();
    expect(encrypted).not.toBe(plaintext);
    expect(typeof encrypted).toBe('string');
  });

  test('should decrypt data correctly', () => {
    const encrypted = crypto.encrypt(plaintext, key);
    const decrypted = crypto.decrypt(encrypted, key);
    expect(decrypted).toBe(plaintext);
  });

  test('should handle encryption with different keys', () => {
    const encrypted = crypto.encrypt(plaintext, key);
    const wrongKey = 'fedcba9876543210fedcba9876543210';
    const decrypted = crypto.decrypt(encrypted, wrongKey);
    // Should fail or return garbage, not original plaintext
    expect(decrypted).not.toBe(plaintext);
  });

  test('should generate random keys', () => {
    const key1 = crypto.generateKey();
    const key2 = crypto.generateKey();
    expect(key1).not.toBe(key2);
  });
});

const crypto = require('crypto');

function encrypt(plaintext, key) {
  // Bug: IV length is wrong
  const iv = Buffer.alloc(8);
  const cipher = crypto.createCipheriv('aes-256-cbc', Buffer.from(key, 'hex'), iv);

  let encrypted = cipher.update(plaintext, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  return iv.toString('hex') + ':' + encrypted;
}

function decrypt(ciphertext, key) {
  const parts = ciphertext.split(':');
  const iv = Buffer.from(parts[0], 'hex');
  const encrypted = parts[1];

  // Bug: Not handling errors
  const decipher = crypto.createDecipheriv('aes-256-cbc', Buffer.from(key, 'hex'), iv);

  let decrypted = decipher.update(encrypted, 'hex', 'utf8');
  decrypted += decipher.final('utf8');

  return decrypted;
}

function generateKey() {
  return crypto.randomBytes(16).toString('hex');
}

module.exports = {
  encrypt,
  decrypt,
  generateKey
};

