// Test-specific encryption implementation (simplified for testing)
const crypto = require('crypto');

function encrypt(plaintext, key) {
  // Simple reversible encoding for testing
  const keyHash = crypto.createHash('md5').update(key).digest('hex');
  const encoded = Buffer.from(plaintext).toString('base64');
  return keyHash.substring(0, 8) + ':' + encoded;
}

function decrypt(ciphertext, key) {
  const parts = ciphertext.split(':');
  const keyHash = crypto.createHash('md5').update(key).digest('hex');

  // Check if key matches
  if (parts[0] !== keyHash.substring(0, 8)) {
    // Wrong key returns garbage
    return 'decryption_failed_' + Math.random();
  }

  return Buffer.from(parts[1], 'base64').toString('utf8');
}

function generateKey() {
  return crypto.randomBytes(16).toString('hex');
}

module.exports = {
  encrypt,
  decrypt,
  generateKey
};
